import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"アカウント追加: OAuthとRefresh Tokenのデュアルチャンネル | Antigravity Tools","description":"Antigravity Toolsのアカウント追加2つの方法を学びます。OAuthワンクリック認証またはRefresh Token手動追加、一括インポート、コールバック失敗対応、アカウントプール検証をサポート。","frontmatter":{"title":"アカウント追加: OAuthとRefresh Tokenのデュアルチャンネル | Antigravity Tools","sidebarTitle":"Googleアカウント追加","subtitle":"アカウント追加：OAuth/Refresh Tokenデュアルチャンネルとベストプラクティス","description":"Antigravity Toolsのアカウント追加2つの方法を学びます。OAuthワンクリック認証またはRefresh Token手動追加、一括インポート、コールバック失敗対応、アカウントプール検証をサポート。","tags":["アカウント管理","OAuth","refresh_token","Google","ベストプラクティス"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"ja/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function d(l,e,s,n,i,h){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="アカウント追加-oauth-refresh-token-デュアルチャンネルとベストプラクティス" tabindex="-1">アカウント追加：OAuth/Refresh Token デュアルチャンネルとベストプラクティス <a class="header-anchor" href="#アカウント追加-oauth-refresh-token-デュアルチャンネルとベストプラクティス" aria-label="Permalink to &quot;アカウント追加：OAuth/Refresh Token デュアルチャンネルとベストプラクティス&quot;">​</a></h1><p>Antigravity Tools では、「アカウント追加」は Google アカウントの <code>refresh_token</code> をローカルアカウントプールに書き込み、後続のリバースプロキシリクエストをローテーションして使用できるようにすることです。OAuth ワンクリック認証を使用するか、<code>refresh_token</code> を直接貼り付けて手動追加できます。</p><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>OAuth または Refresh Token を使用して、Google アカウントを Antigravity Tools のアカウントプールに追加する</li><li>認証リンクをコピー/手動で開き、コールバック成功後に自動的に追加を完了する</li><li><code>refresh_token</code> の取得、コールバックが <code>localhost</code> に接続できないなどの問題に遭遇した場合の対処方法を知る</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><ul><li>「OAuth認証」をクリックしてもずっと読み込み中のまま、またはブラウザが <code>localhost refused to connect</code> と表示される</li><li>認証は成功したが、「Refresh Tokenが取得できません」と表示される</li><li>手元に <code>refresh_token</code> しかなく、一度に一括インポートする方法がわからない</li></ul><h2 id="いつこの方法を使用するか" tabindex="-1">いつこの方法を使用するか <a class="header-anchor" href="#いつこの方法を使用するか" aria-label="Permalink to &quot;いつこの方法を使用するか&quot;">​</a></h2><ul><li>最も安定した方法でアカウントを追加したい場合（OAuth優先）</li><li>移行/バックアップを重視したい場合（Refresh Tokenは「アカウントプール資産」に適している）</li><li>多くのアカウントを追加し、<code>refresh_token</code> を一括インポートしたい場合（テキスト/JSONからの抽出をサポート）</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><ul><li>Antigravity Tools デスクトップ版をインストールし、開くことができる</li><li>入口を知っている：左側のナビゲーションから <code>Accounts</code> ページに入る（ルートは <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>）</li></ul><div class="info custom-block"><p class="custom-block-title">このレッスンの2つのキーワード</p><p><strong>OAuth</strong>：「ブラウザでログインして認証」するフロー。Antigravity Tools はローカルで一時的にコールバックアドレスを起動し（<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>、システムの IPv4/IPv6 監視状況に応じて自動選択）、ブラウザが <code>code</code> を持って戻ってきた後にトークンと交換します。（実装は <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>）</p><p><strong>refresh_token</strong>：「access_token を長期間更新できる認証情報」。プロジェクトでアカウントを追加する際、これを使用して最初に access_token を取得し、Google から実際のメールアドレスを取得し、フロントエンドで入力した email を無視します。（実装は <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>）</p></div><h2 id="コアアイデア" tabindex="-1">コアアイデア <a class="header-anchor" href="#コアアイデア" aria-label="Permalink to &quot;コアアイデア&quot;">​</a></h2><p>Antigravity Tools の「アカウント追加」は、最終的に使用可能な <code>refresh_token</code> を取得し、アカウント情報をローカルアカウントプールに書き込むことを目的としています。</p><ul><li><strong>OAuth チャンネル</strong>：アプリケーションが認証リンクを生成し、ローカルコールバックを監視します。認証完了後、自動的にトークンを交換してアカウントを保存します（<code>prepare_oauth_url</code>、<code>start_oauth_login</code>、<code>complete_oauth_login</code> を参照）</li><li><strong>Refresh Token チャンネル</strong>：<code>refresh_token</code> を直接貼り付け、アプリケーションがそれを使用して access_token を更新し、Google から実際のメールアドレスを取得して保存します（<code>add_account</code> を参照）</li></ul><h2 id="手順に従って進める" tabindex="-1">手順に従って進める <a class="header-anchor" href="#手順に従って進める" aria-label="Permalink to &quot;手順に従って進める&quot;">​</a></h2><h3 id="ステップ-1-「アカウント追加」ダイアログを開く" tabindex="-1">ステップ 1：「アカウント追加」ダイアログを開く <a class="header-anchor" href="#ステップ-1-「アカウント追加」ダイアログを開く" aria-label="Permalink to &quot;ステップ 1：「アカウント追加」ダイアログを開く&quot;">​</a></h3><p><strong>なぜ</strong> すべての追加入口は <code>Accounts</code> ページで統一されています。</p><p>操作：<code>Accounts</code> ページに入り、右側の <strong>Add Account</strong> ボタンをクリックします（コンポーネント：<code>AddAccountDialog</code>）。</p><p><strong>次のように表示されます</strong>：3つのタブページを含むダイアログが表示されます：<code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code>（<code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code> を参照）</p><h3 id="ステップ-2-優先して-oauth-ワンクリック認証を使用する-推奨" tabindex="-1">ステップ 2：優先して OAuth ワンクリック認証を使用する（推奨） <a class="header-anchor" href="#ステップ-2-優先して-oauth-ワンクリック認証を使用する-推奨" aria-label="Permalink to &quot;ステップ 2：優先して OAuth ワンクリック認証を使用する（推奨）&quot;">​</a></h3><p><strong>なぜ</strong> これが製品のデフォルト推奨パスです。アプリケーションが認証リンクを生成し、デフォルトブラウザを自動的に開き、コールバックが戻ってきたら自動的に保存を完了します。</p><ol><li><code>OAuth</code> タブに切り替えます。</li><li>最初に認証リンクをコピーします。ダイアログが開くと、自動的に <code>prepare_oauth_url</code> を呼び出して URL を事前生成します（フロントエンド呼び出しは <code>AddAccountDialog.tsx:111-125</code>、バックエンド生成と監視は <code>oauth_server.rs</code>）。</li><li><strong>Start OAuth</strong> をクリックします（フロントエンド <code>startOAuthLogin()</code> / バックエンド <code>start_oauth_login</code> に対応）、アプリケーションにデフォルトブラウザを開かせ、コールバックを待機させます。</li></ol><p><strong>次のように表示されます</strong>：</p><ul><li>ダイアログにコピー可能な認証リンクが表示されます（イベント名：<code>oauth-url-generated</code>）</li><li>ブラウザが Google 認証ページを開きます。認証後にローカルアドレスにリダイレクトし、「Authorization Successful!」と表示されます（<code>oauth_success_html()</code>）</li></ul><h3 id="ステップ-3-oauth-が自動的に完了しない場合、「oauth-完了」で手動で終了する" tabindex="-1">ステップ 3：OAuth が自動的に完了しない場合、「OAuth 完了」で手動で終了する <a class="header-anchor" href="#ステップ-3-oauth-が自動的に完了しない場合、「oauth-完了」で手動で終了する" aria-label="Permalink to &quot;ステップ 3：OAuth が自動的に完了しない場合、「OAuth 完了」で手動で終了する&quot;">​</a></h3><p><strong>なぜ</strong> OAuth フローは2つのパートに分かれます：ブラウザ認証で <code>code</code> を取得し、その後アプリケーションが <code>code</code> でトークンと交換します。「Start OAuth」をクリックしなくても、認証リンクを手動で開いてコールバックを完了すれば、ダイアログは自動的に終了しようとします。終了に失敗した場合、手動で一度クリックできます。</p><ol><li>「リンクをコピーして自分のブラウザで開く」場合（デフォルトブラウザではない）、認証コールバックが戻ってくると、アプリケーションは <code>oauth-callback-received</code> イベントを受け取り、自動的に <code>completeOAuthLogin()</code> を呼び出します（<code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code> を参照）。</li><li>自動完了が表示されない場合、ダイアログ内の <strong>Finish OAuth</strong> をクリックします（バックエンド <code>complete_oauth_login</code> に対応）。</li></ol><p><strong>次のように表示されます</strong>：ダイアログが成功を通知し、自動的に閉じます。<code>Accounts</code> リストに新しいアカウントが表示されます。</p><div class="tip custom-block"><p class="custom-block-title">小技：コールバックが接続できない場合はリンクをコピー優先</p><p>バックエンドは可能な限り同時に IPv6 <code>::1</code> と IPv4 <code>127.0.0.1</code> を監視し、監視状況に応じて <code>localhost/127.0.0.1/[::1]</code> をコールバックアドレスとして選択します。これは主に「ブラウザが localhost を IPv6 に解釈する」ことによる接続失敗を回避するためです。（<code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code> を参照）</p></div><h3 id="ステップ-4-refresh-token-で手動追加-一括対応" tabindex="-1">ステップ 4：Refresh Token で手動追加（一括対応） <a class="header-anchor" href="#ステップ-4-refresh-token-で手動追加-一括対応" aria-label="Permalink to &quot;ステップ 4：Refresh Token で手動追加（一括対応）&quot;">​</a></h3><p><strong>なぜ</strong><code>refresh_token</code> が取得できない場合（または「移行可能資産」を重視する場合）、Refresh Token で直接追加する方が制御しやすいです。</p><ol><li><code>Refresh Token</code> タブに切り替えます。</li><li><code>refresh_token</code> をテキストボックスに貼り付けます。</li></ol><p>サポートされる入力形式（フロントエンドが解析して一括追加）：</p><table tabindex="0"><thead><tr><th>入力タイプ</th><th>例</th><th>解析ロジック</th></tr></thead><tbody><tr><td>純粋なトークンテキスト</td><td><code>1//abc...</code></td><td>正規表現抽出：<code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code>（<code>AddAccountDialog.tsx:213-220</code> を参照）</td></tr><tr><td>大きなテキストに含まれる</td><td>ログ/エクスポートテキストに複数の <code>1//...</code> が含まれる</td><td>正規表現一括抽出と重複排除（<code>AddAccountDialog.tsx:213-224</code> を参照）</td></tr><tr><td>JSON 配列</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>配列を解析して <code>item.refresh_token</code> を取得（<code>AddAccountDialog.tsx:198-207</code> を参照）</td></tr></tbody></table><p><strong>Confirm</strong> をクリックすると、ダイアログはトークン数に応じて個別に <code>onAdd(&quot;&quot;, token)</code> を呼び出します（<code>AddAccountDialog.tsx:231-248</code> を参照）、最終的にバックエンド <code>add_account</code> に到達します。</p><p><strong>次のように表示されます</strong>：</p><ul><li>ダイアログが一括進行状況を表示します（例：<code>1/5</code>）</li><li>成功後、<code>Accounts</code> リストに新しいアカウントが表示されます</li></ul><h3 id="ステップ-5-「アカウントプールが使用可能」を確認する" tabindex="-1">ステップ 5：「アカウントプールが使用可能」を確認する <a class="header-anchor" href="#ステップ-5-「アカウントプールが使用可能」を確認する" aria-label="Permalink to &quot;ステップ 5：「アカウントプールが使用可能」を確認する&quot;">​</a></h3><p><strong>なぜ</strong> 追加成功は「すぐに安定して使用できる」という意味ではありません。バックエンドは追加後に自動的に「クォータ更新」を1回トリガーし、Proxy が実行中にトークンプールのリロードを試み、変更を即座に有効にします。</p><p>次の 2 つのシグナルで確認できます：</p><ol><li>アカウントがリストに表示され、メールアドレスが表示されます（メールアドレスはバックエンド <code>get_user_info</code> から取得、入力した email ではありません）。</li><li>アカウントクォータ/サブスクリプション情報の更新が開始されます（バックエンドは自動的に <code>internal_refresh_account_quota</code> を呼び出します）。</li></ol><p><strong>次のように表示されます</strong>：追加後、手動で更新をクリックする必要はありません。アカウントがクォータ情報を表示し始めます（成功かどうかは実際のインターフェース表示に基づきます）。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>アカウントリストに追加されたアカウントのメールアドレスが表示される</li><li>受け入れられる時間より長く「loading」状態にとどまっていない（OAuth コールバック完了後はすぐに終了するはず）</li><li>Proxy を実行している場合、追加されたアカウントがすぐにスケジュールに参加できる（バックエンドはリロードを試みます）</li></ul><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><h3 id="_1-oauth-が「refresh-tokenが取得できません」と表示する場合" tabindex="-1">1) OAuth が「Refresh Tokenが取得できません」と表示する場合 <a class="header-anchor" href="#_1-oauth-が「refresh-tokenが取得できません」と表示する場合" aria-label="Permalink to &quot;1) OAuth が「Refresh Tokenが取得できません」と表示する場合&quot;">​</a></h3><p>バックエンドは <code>start_oauth_login/complete_oauth_login</code> で <code>refresh_token</code> が存在するか明示的にチェックします。存在しない場合、解決策を含むエラー情報が返されます（<code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code> を参照）。</p><p>ソースコードの指示に従って処理します：</p><ol><li><code>https://myaccount.google.com/permissions</code> を開きます。</li><li><strong>Antigravity Tools</strong> のアクセス権限を取り消します。</li><li>アプリケーションに戻って OAuth を再試行します。</li></ol><blockquote><p>このレッスンの Refresh Token チャンネルに直接切り替えることもできます。</p></blockquote><h3 id="_2-ブラウザが-localhost-refused-to-connect-と表示する場合" tabindex="-1">2) ブラウザが <code>localhost refused to connect</code> と表示する場合 <a class="header-anchor" href="#_2-ブラウザが-localhost-refused-to-connect-と表示する場合" aria-label="Permalink to &quot;2) ブラウザが `localhost refused to connect` と表示する場合&quot;">​</a></h3><p>OAuth コールバックにはブラウザがローカルコールバックアドレスをリクエストする必要があります。失敗率を下げるため、バックエンドは：</p><ul><li><code>127.0.0.1</code> と <code>::1</code> の両方を同時に監視しようとします</li><li>両方が使用可能な場合のみ <code>localhost</code> を使用し、そうでない場合は <code>127.0.0.1</code> または <code>[::1]</code> を強制的に使用します</li></ul><p>対応する実装は <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code> を参照してください。</p><h3 id="_3-他のタブに切り替えると-oauth-準備がキャンセルされる" tabindex="-1">3) 他のタブに切り替えると OAuth 準備がキャンセルされる <a class="header-anchor" href="#_3-他のタブに切り替えると-oauth-準備がキャンセルされる" aria-label="Permalink to &quot;3) 他のタブに切り替えると OAuth 準備がキャンセルされる&quot;">​</a></h3><p>ダイアログが <code>OAuth</code> から他のタブに切り替わると、フロントエンドは <code>cancelOAuthLogin()</code> を呼び出し、URL をクリアします（<code>AddAccountDialog.tsx:127-136</code> を参照）。</p><p>認証プロセス中の場合、タブを急いで切り替えないでください。</p><h3 id="_4-refresh-token-の正しい-間違った例" tabindex="-1">4) Refresh Token の正しい/間違った例 <a class="header-anchor" href="#_4-refresh-token-の正しい-間違った例" aria-label="Permalink to &quot;4) Refresh Token の正しい/間違った例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>例</th><th>識別されるか</th><th>理由</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td><code>1//</code> 接頭辞ルールに適合（<code>AddAccountDialog.tsx:215-219</code> を参照）</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>フロントエンド抽出ルールに適合せず、無効な入力とみなされます</td></tr></tbody></table><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>OAuth：「速さ」に適しており、リンクをコピーして常用ブラウザで開き、自動/手動で終了することも可能</li><li>Refresh Token：「安定」と「移行性」に適しており、テキスト/JSON から <code>1//...</code> を一括抽出をサポート</li><li><code>refresh_token</code> が取得できない場合、エラー指示に従って認証を取り消して再試行するか、直接 Refresh Token に切り替える</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><p>次のレッスンでは、より確実なことを行います：アカウントプールを「移行可能資産」にします。</p><blockquote><p><strong><a href="./../backup-migrate/">アカウントバックアップと移行：インポート/エクスポート、V1/DB ホットマイグレーション</a></strong> に行ってください。</p></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Accounts ページに追加ダイアログをマウント</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>OAuth URL 事前生成 + コールバックイベント自動終了</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L49-L125" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>49-125</td></tr><tr><td>OAuth コールバックイベントが <code>completeOAuthLogin()</code> をトリガー</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Refresh Token 一括解析と重複排除</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>フロントエンドが Tauri コマンドを呼び出す（add/OAuth/cancel）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>バックエンド add_account：email を無視、refresh_token を使用して実際のメールアドレスを取得し保存</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>バックエンド OAuth：refresh_token 欠如をチェックし、認証取り消しソリューションを提供</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>OAuth コールバック server：IPv4/IPv6 を同時に監視し redirect_uri を選択</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>重要イベント名</strong>：</p><ul><li><code>oauth-url-generated</code>：バックエンドが OAuth URL を生成した後、フロントエンドに送信（<code>oauth_server.rs:250-252</code> を参照）</li><li><code>oauth-callback-received</code>：バックエンドがコールバックを受け取り、code を解析した後、フロントエンドに通知（<code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code> を参照）</li></ul><p><strong>重要コマンド</strong>：</p><ul><li><code>prepare_oauth_url</code>：認証リンクを事前生成し、コールバック監視を開始（<code>src-tauri/src/commands/mod.rs:469-473</code> を参照）</li><li><code>start_oauth_login</code>：デフォルトブラウザを開き、コールバックを待機（<code>src-tauri/src/commands/mod.rs:339-401</code> を参照）</li><li><code>complete_oauth_login</code>：ブラウザを開かず、コールバックのみを待機し、トークン交換を完了（<code>src-tauri/src/commands/mod.rs:405-467</code> を参照）</li><li><code>add_account</code>：refresh_token を使用してアカウントを保存（<code>src-tauri/src/commands/mod.rs:19-60</code> を参照）</li></ul></details>',67)])])}const b=o(c,[["render",d]]);export{g as __pageData,b as default};
